import { useState, useEffect, useRef } from 'react';
import axios from 'axios';

const API = axios.create({ baseURL: 'http://localhost:5000/api' });

const TYPE_COLORS = {
  'Government':      '#2d6a4f',
  'Super Specialty': '#1d3557',
  'Multi Specialty': '#4895ef',
  'Private':         '#f4a261',
  'Nursing Home':    '#e63946',
  'Clinic':          '#7b2d8b',
};

const TYPE_EMOJI = {
  'Government':      '🏛️',
  'Super Specialty': '🏥',
  'Multi Specialty': '🏨',
  'Private':         '🏪',
  'Nursing Home':    '🏠',
  'Clinic':          '🩺',
};

export default function NearbyHospitals() {
  const [hospitals, setHospitals] = useState([]);
  const [filtered, setFiltered] = useState([]);
  const [selectedHospital, setSelectedHospital] = useState(null);
  const [userLocation, setUserLocation] = useState(null);
  const [mapLoaded, setMapLoaded] = useState(false);
  const [search, setSearch] = useState('');
  const [typeFilter, setTypeFilter] = useState('All');
  const [emergencyOnly, setEmergencyOnly] = useState(false);
  const [loading, setLoading] = useState(true);

  const mapRef = useRef(null);
  const mapInstance = useRef(null);
  const markersRef = useRef([]);

  useEffect(() => { loadHospitals(); loadLeaflet(); getUserLocation(); }, []);
  useEffect(() => { applyFilters(); }, [hospitals, search, typeFilter, emergencyOnly]);
  useEffect(() => { if (mapLoaded && mapRef.current && !mapInstance.current) initMap(); }, [mapLoaded, userLocation]);
  useEffect(() => { if (mapInstance.current && filtered.length > 0) updateMarkers(); }, [filtered, mapLoaded]);

  const loadHospitals = async () => {
    try {
      const res = await API.get('/hospitals/');
      setHospitals(res.data);
      setFiltered(res.data);
    } catch {} finally { setLoading(false); }
  };

  const loadLeaflet = () => {
    if (window.L) { setMapLoaded(true); return; }
    const link = document.createElement('link');
    link.rel = 'stylesheet';
    link.href = 'https://unpkg.com/leaflet@1.9.4/dist/leaflet.css';
    document.head.appendChild(link);
    const script = document.createElement('script');
    script.src = 'https://unpkg.com/leaflet@1.9.4/dist/leaflet.js';
    script.onload = () => setMapLoaded(true);
    document.head.appendChild(script);
  };

  const getUserLocation = () => {
    if (!navigator.geolocation) { setUserLocation({ lat: 26.9124, lng: 75.7873 }); return; }
    navigator.geolocation.getCurrentPosition(
      pos => setUserLocation({ lat: pos.coords.latitude, lng: pos.coords.longitude }),
      () => setUserLocation({ lat: 26.9124, lng: 75.7873 })
    );
  };

  const initMap = () => {
    if (!window.L || !mapRef.current) return;
    const L = window.L;
    const center = userLocation ? [userLocation.lat, userLocation.lng] : [26.9124, 75.7873];
    const map = L.map(mapRef.current).setView(center, 12);
    L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', { attribution: '© OpenStreetMap contributors' }).addTo(map);
    if (userLocation) {
      const userIcon = L.divIcon({ className: '', html: `<div style="width:16px;height:16px;background:#4895ef;border:3px solid white;border-radius:50%;box-shadow:0 2px 8px rgba(0,0,0,0.4)"></div>`, iconSize: [16,16], iconAnchor: [8,8] });
      L.marker([userLocation.lat, userLocation.lng], { icon: userIcon }).addTo(map).bindPopup('<b>📍 Your Location</b>');
    }
    mapInstance.current = map;
    updateMarkers();
  };

  const updateMarkers = () => {
    if (!window.L || !mapInstance.current) return;
    const L = window.L;
    markersRef.current.forEach(m => m.marker.remove());
    markersRef.current = [];
    filtered.forEach(hospital => {
      if (!hospital.latitude || !hospital.longitude) return;
      const color = TYPE_COLORS[hospital.hospital_type] || '#666';
      const emoji = TYPE_EMOJI[hospital.hospital_type] || '🏥';
      const icon = L.divIcon({ className: '', html: `<div style="width:34px;height:34px;background:${color};border:2px solid white;border-radius:50%;display:flex;align-items:center;justify-content:center;font-size:15px;box-shadow:0 3px 10px rgba(0,0,0,0.3);cursor:pointer">${emoji}</div>`, iconSize:[34,34], iconAnchor:[17,17] });
      const marker = L.marker([parseFloat(hospital.latitude), parseFloat(hospital.longitude)], { icon })
        .addTo(mapInstance.current)
        .bindPopup(`<div style="font-family:DM Sans,sans-serif;min-width:220px;padding:4px"><div style="font-weight:700;font-size:14px;margin-bottom:4px">${hospital.name}</div><div style="display:inline-block;padding:2px 8px;border-radius:99px;font-size:11px;background:${color}22;color:${color};font-weight:600;margin-bottom:6px">${hospital.hospital_type}</div><hr style="margin:6px 0;border:none;border-top:1px solid #eee"/><div style="font-size:12px;line-height:1.8">📍 ${hospital.address}<br/>📞 ${hospital.phone}<br/>🛏️ ${hospital.total_beds || 'N/A'} beds<br/>⏰ ${hospital.timings}<br/>⭐ ${hospital.rating}/5${hospital.has_emergency ? '<br/>🚨 <b>Emergency Available</b>' : ''}${hospital.has_icu ? '<br/>🏥 ICU Available' : ''}${hospital.has_ambulance ? '<br/>🚑 Ambulance Available' : ''}</div></div>`);
      marker.on('click', () => setSelectedHospital(hospital));
      markersRef.current.push({ marker, hospital });
    });
  };

  const applyFilters = () => {
    let result = [...hospitals];
    if (search) { const s = search.toLowerCase(); result = result.filter(h => h.name.toLowerCase().includes(s) || (h.area||'').toLowerCase().includes(s) || (h.specializations||'').toLowerCase().includes(s)); }
    if (typeFilter !== 'All') result = result.filter(h => h.hospital_type === typeFilter);
    if (emergencyOnly) result = result.filter(h => h.has_emergency);
    setFiltered(result);
  };

  const focusHospital = (hospital) => {
    setSelectedHospital(hospital);
    if (!mapInstance.current || !hospital.latitude) return;
    mapInstance.current.setView([parseFloat(hospital.latitude), parseFloat(hospital.longitude)], 16);
    const found = markersRef.current.find(m => m.hospital.id === hospital.id);
    if (found) found.marker.openPopup();
  };

  const hospitalTypes = ['All','Government','Super Specialty','Multi Specialty','Private','Nursing Home','Clinic'];

  return (
    <div className="animate-fade">
      <div style={{ marginBottom: 20 }}>
        <h1 style={{ fontFamily: 'var(--font-display)', fontSize: 28, marginBottom: 4 }}>🗺️ Nearby Hospitals</h1>
        <p style={{ color: 'var(--text-muted)' }}>{filtered.length} hospitals found across Jaipur</p>
      </div>

      <div className="card" style={{ marginBottom: 16 }}>
        <div className="card-body" style={{ padding: '14px 20px' }}>
          <div style={{ display: 'flex', gap: 12, flexWrap: 'wrap', alignItems: 'center' }}>
            <input className="form-control" style={{ maxWidth: 260 }} placeholder="🔎 Search hospital or area..." value={search} onChange={e => setSearch(e.target.value)} />
            <div style={{ display: 'flex', gap: 6, flexWrap: 'wrap' }}>
              {hospitalTypes.map(t => (
                <button key={t} className={`btn btn-sm ${typeFilter === t ? 'btn-primary' : 'btn-outline'}`} onClick={() => setTypeFilter(t)}>
                  {TYPE_EMOJI[t] || '🏥'} {t}
                </button>
              ))}
            </div>
            <label style={{ display: 'flex', alignItems: 'center', gap: 8, fontSize: 14, cursor: 'pointer' }}>
              <input type="checkbox" checked={emergencyOnly} onChange={e => setEmergencyOnly(e.target.checked)} />
              🚨 Emergency Only
            </label>
          </div>
        </div>
      </div>

      <div style={{ display: 'flex', gap: 12, flexWrap: 'wrap', marginBottom: 14 }}>
        {Object.entries(TYPE_COLORS).map(([type, color]) => (
          <div key={type} style={{ display: 'flex', alignItems: 'center', gap: 6, fontSize: 12 }}>
            <div style={{ width: 12, height: 12, borderRadius: '50%', background: color }} />{type}
          </div>
        ))}
      </div>

      <div style={{ display: 'grid', gridTemplateColumns: '320px 1fr', gap: 16, alignItems: 'start' }}>
        <div className="card" style={{ maxHeight: 580, overflow: 'hidden', display: 'flex', flexDirection: 'column' }}>
          <div className="card-header" style={{ flexShrink: 0 }}><h2>Hospitals ({filtered.length})</h2></div>
          <div style={{ overflowY: 'auto', flex: 1 }}>
            {loading ? <div className="loading-center"><div className="spinner" /></div>
            : filtered.length === 0 ? <div className="empty-state"><div className="empty-icon">🏥</div><h3>No hospitals found</h3></div>
            : filtered.map(h => (
              <div key={h.id} onClick={() => focusHospital(h)} style={{ padding: '12px 16px', borderBottom: '1px solid var(--border)', cursor: 'pointer', background: selectedHospital?.id === h.id ? 'var(--success-light)' : 'white', borderLeft: selectedHospital?.id === h.id ? '3px solid var(--primary)' : '3px solid transparent', transition: 'all 0.15s' }}>
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
                  <div style={{ flex: 1 }}>
                    <div style={{ fontWeight: 600, fontSize: 13, marginBottom: 3, lineHeight: 1.3 }}>{h.name}</div>
                    <span style={{ padding: '1px 7px', borderRadius: 99, fontSize: 10, fontWeight: 600, background: (TYPE_COLORS[h.hospital_type]||'#666')+'22', color: TYPE_COLORS[h.hospital_type]||'#666' }}>{h.hospital_type}</span>
                    <div style={{ fontSize: 11, color: 'var(--text-muted)', marginTop: 4 }}>📍 {h.area}</div>
                    <div style={{ display: 'flex', gap: 8, marginTop: 4, fontSize: 11 }}>
                      {h.has_emergency && <span style={{ color: '#e63946' }}>🚨 ER</span>}
                      {h.has_icu && <span style={{ color: '#4895ef' }}>🏥 ICU</span>}
                      {h.has_ambulance && <span style={{ color: '#2d6a4f' }}>🚑</span>}
                    </div>
                  </div>
                  <div style={{ fontSize: 12, color: '#f4a261', fontWeight: 600 }}>⭐ {h.rating}</div>
                </div>
              </div>
            ))}
          </div>
        </div>

        <div ref={mapRef} style={{ height: 580, borderRadius: 'var(--radius)', overflow: 'hidden', border: '1px solid var(--border)' }} />
      </div>

      {selectedHospital && (
        <div className="card animate-slide" style={{ marginTop: 16 }}>
          <div className="card-body">
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', flexWrap: 'wrap', gap: 16 }}>
              <div style={{ flex: 1 }}>
                <div style={{ display: 'flex', alignItems: 'center', gap: 12, marginBottom: 8 }}>
                  <span style={{ fontSize: 32 }}>{TYPE_EMOJI[selectedHospital.hospital_type]||'🏥'}</span>
                  <div>
                    <h2 style={{ fontSize: 20, fontWeight: 700 }}>{selectedHospital.name}</h2>
                    <span style={{ padding: '2px 10px', borderRadius: 99, fontSize: 12, fontWeight: 600, background: (TYPE_COLORS[selectedHospital.hospital_type]||'#666')+'22', color: TYPE_COLORS[selectedHospital.hospital_type]||'#666' }}>{selectedHospital.hospital_type}</span>
                  </div>
                </div>
                <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))', gap: 8, fontSize: 13, color: 'var(--text-muted)' }}>
                  <span>📍 {selectedHospital.address}</span>
                  <span>🏘️ {selectedHospital.area}, {selectedHospital.city}</span>
                  <span>📞 {selectedHospital.phone}</span>
                  {selectedHospital.emergency_phone && <span>🚨 Emergency: {selectedHospital.emergency_phone}</span>}
                  <span>⏰ {selectedHospital.timings}</span>
                  {selectedHospital.total_beds && <span>🛏️ {selectedHospital.total_beds} Beds</span>}
                  <span>⭐ Rating: {selectedHospital.rating}/5</span>
                </div>
                {selectedHospital.specializations && (
                  <div style={{ marginTop: 10 }}>
                    <div style={{ fontSize: 12, color: 'var(--text-muted)', marginBottom: 6 }}>Specializations:</div>
                    <div style={{ display: 'flex', flexWrap: 'wrap', gap: 6 }}>
                      {selectedHospital.specializations.split(',').map((s,i) => (
                        <span key={i} style={{ padding: '3px 10px', borderRadius: 99, fontSize: 12, background: 'var(--success-light)', color: 'var(--primary-dark)', fontWeight: 500 }}>{s.trim()}</span>
                      ))}
                    </div>
                  </div>
                )}
              </div>
              <div style={{ display: 'flex', flexDirection: 'column', gap: 8, flexShrink: 0 }}>
                {selectedHospital.has_emergency && <span style={{ padding: '6px 14px', borderRadius: 8, background: '#fff0f0', color: '#e63946', fontSize: 13, fontWeight: 600 }}>🚨 Emergency Available</span>}
                {selectedHospital.has_icu && <span style={{ padding: '6px 14px', borderRadius: 8, background: '#e0f0ff', color: '#1d4ed8', fontSize: 13, fontWeight: 600 }}>🏥 ICU Available</span>}
                {selectedHospital.has_ambulance && <span style={{ padding: '6px 14px', borderRadius: 8, background: 'var(--success-light)', color: 'var(--primary-dark)', fontSize: 13, fontWeight: 600 }}>🚑 Ambulance Available</span>}
                <button className="btn btn-outline btn-sm" onClick={() => setSelectedHospital(null)}>Close ×</button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
